&-operation {
  width: @size-6;
  width: var(--am-operation-icon-width, @size-6);
  height: @size-6;
  height: var(--am-operation-icon-height, @size-6);
  overflow: hidden;
  text-align: center;
  line-height: @size-6;
  line-height: var(--am-title-operation-lineHeight, @size-6);
  margin-left: @h-spacing-standard;
  margin-left: var(--am-title-operation-marginLeft, @h-spacing-standard);
  &-icon {
    font-size: @icon-size-xs;
    font-size: var(--am-title-operation-icon-size, @icon-size-xs);
    color: @color-text-weak;
    color: var(--am-title-operation-icon-color, @color-text-weak);
  }
}

// Default
.btn-default() {
    .button-variant(@btn-default-color; @btn-default-bg; @btn-default-border);

    &:hover
    //&:focus
    {
        .button-color(tint(@primary-color, 20%); white; tint(@primary-color, 20%));
    }
    &:active,
    &.active {
        .button-color(shade(@primary-color, 5%); white; shade(@primary-color, 5%));
    }
    .active-btn-color(@primary-color);
}

// Primary
.btn-primary() {
    .button-variant(@btn-primary-color; @btn-primary-bg; @primary-color);

    &:hover,
    //&:focus,
    &:active,
    &.active {
        color: @btn-primary-color;
    }
    .active-btn-color(@primary-color);
}

// Circle for Icon
.btn-circle(@btnClassName: ivu-btn) {
    border-radius: @btn-circle-size;

    &.@{btnClassName}-large{
        border-radius: @btn-circle-size-large;
    }

    &.@{btnClassName}-size{
        border-radius: @btn-circle-size-small;
    }

    &.@{btnClassName}-icon-only{
        .square(@btn-circle-size);
        .button-size(0; @font-size-base + 2; 50%);

        &.@{btnClassName}-large{
            .square(@btn-circle-size-large);
            .button-size(0; @btn-font-size-large + 2; 50%);
        }

        &.@{btnClassName}-small{
            .square(@btn-circle-size-small);
            .button-size(0; @font-size-base; 50%);
        }
    }
}

&-card {
  background: linear-gradient(180deg, var(--r-surface) 0%, var(--r-surface-2) 100%);
  border: 1px solid var(--r-line);
  padding: 18px 18px 16px;
  position: relative;
  overflow: hidden;
  transition: border-color .15s, box-shadow .15s;

  &:hover {
    border-color: var(--r-accent);
    box-shadow: 0 0 0 1px var(--r-accent-soft), 0 0 24px -8px var(--r-accent);
  }

  &::before {
    content: '';
    position: absolute; top: 0; right: 0;
    width: 16px; height: 16px;
    background: var(--r-bg);
    clip-path: polygon(100% 0, 0 0, 100% 100%);
    border-left: 1px solid var(--r-line);
    border-bottom: 1px solid var(--r-line);
  }

  &::after {
    content: '';
    position: absolute; inset: 0;
    background: repeating-linear-gradient(180deg, transparent 0 3px, var(--r-scanline-2) 3px 4px);
    pointer-events: none;
  }
}

&-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 8px;

  li {
    display: flex;
    align-items: center;
    gap: 10px;
    font-family: 'JetBrains Mono', monospace;
    font-size: 11px;
    letter-spacing: 0.08em;
    color: var(--r-text);
  }

  .pip {
    width: 10px;
    height: 10px;
    transform: rotate(45deg);
    flex: 0 0 10px;
    box-shadow: 0 0 8px currentColor;

    &.legendary { background: var(--r-gold);  color: var(--r-gold); }
    &.epic      { background: var(--r-epic);  color: var(--r-epic); }
    &.rare      { background: var(--r-rare);  color: var(--r-rare); }
    &.common    { background: var(--r-common); color: var(--r-common); box-shadow: none; }
  }
}

a {
	display: flex;
	align-items: center;
	text-decoration: none;
	margin-right: 20px;
	&>span {
		background-color: rgba(96,125,139,.05);
		line-height: 2.4;
		transition: all .15s;
		padding: 0 12px;
		margin-bottom: 15px;
		border-radius: 6px;
		position: relative;
		top: 0;
		color: #43576B;
		font-weight: 400;
		font-size: 16px;
		&:hover {
			top: -2px;
			background-color: #607d8b;
			color: #ffffff;
			transition: all .3s ease-in-out;
		}
		&>i {
			text-align: center;
			color: #F56C6C;
			font-size: 15px;
			font-weight: 500;
		}
	}
}

pre {
	font-size: .85em;
	line-height: 1.5em;
	display: flex;
	max-width: 1000px;
	position: relative;
	&:after {
		position: absolute;
		left: 20px;
		top: 30px;
		width: 12px;
		height: 12px;
		border-radius: 50%;
		background: #fc625d;
		-webkit-box-shadow: 20px 0 #fdbc40, 40px 0 #35cd4b;
		box-shadow: 20px 0 #fdbc40, 40px 0 #35cd4b;
		content: ' ';
	}
	code {
		flex: 1;
		text-align: left;
		width: fit-content;
		padding: 40px 20px 20px 20px;
		margin: 20px 0;
		white-space: pre;
		word-spacing: normal;
		word-break: normal;
		word-wrap: normal;
	}
}

&-content {
  display: flex;
  align-items: var(--align-items);
  justify-content: flex-start;
  border-top: var(--border-inner);
  padding-right: var(--padding-right);
  &-prefix {
    width: var(--prefix-width);
    flex: none;
    padding-right: var(--prefix-padding-right);
  }
  &-main {
    flex: auto;
    padding: 12px 0;
  }
  &-extra {
    flex: none;
    padding-left: 12px;
    font-size: var(--adm-font-size-7);
    color: var(--adm-color-weak);
    max-width: var(--extra-max-width);
  }
  &-arrow {
    flex: none;
    display: flex;
    align-items: center;
    margin-left: 4px;
    color: var(--adm-color-light);
    font-size: 19px;
  }
}

&-svg {
  width: 100%;
  height: 100%;
  > .@{class-prefix-progress-circle}-track,
  .@{class-prefix-progress-circle}-fill {
    stroke-width: var(--track-width);
    r: var(--radius);
    cx: calc(var(--size) / 2);
    cy: calc(var(--size) / 2);
    transform: rotate(-90deg);
    transform-origin: 50% 50%;
  }
  > .@{class-prefix-progress-circle}-track {
    stroke: var(--track-color);
  }
  > .@{class-prefix-progress-circle}-fill {
    transition: stroke-dashoffset 0.35s;
    stroke: var(--fill-color);
    stroke-dasharray: var(--circumference);
    stroke-dashoffset: calc(
      var(--circumference) * (1 - var(--percent) / 100)
    );
    stroke-linecap: round;
  }
}

&-disabled {
  .@{class-prefix-slider}-mark,
  .@{class-prefix-slider}-thumb-icon {
    opacity: 0.4;
  }
  .@{class-prefix-slider}-tick-active,
  .@{class-prefix-slider}-fill {
    &::after {
      content: '';
      position: absolute;
      left: 0;
      top: 0;
      right: 0;
      bottom: 0;
      border-radius: inherit;
      background-color: rgba(255, 255, 255, 0.6);
    }
  }
  .@{class-prefix-slider}-thumb {
    cursor: not-allowed;
    box-shadow: 0 2px 5px 0 rgba(0, 0, 0, 0.06);
  }
  .@{class-prefix-slider}-mark-text,
  .@{class-prefix-slider}-tick {
    cursor: not-allowed;
    box-shadow: none;
  }
}

body {
	font-weight: 500;
	color: var(--body-color, #7b7b7d);
	background-color: var(--body-bg-color);
	letter-spacing: 0.05em;
	overflow-x: hidden;
	margin: 0;
	margin-right: calc(100% - 100vw);
	padding: 10px;
	height: 100vh;
	scroll-behavior: smooth;
	-webkit-font-smoothing: antialiased;

	&::before {
		content: "";
		position: fixed;
		left: 10px;
		top: 10px;
		width: calc(100% - 20px);
		height: calc(100% - 20px);
		z-index: 9999;
		pointer-events: none;
		box-shadow: 0 0 0 20px var(--body-bg-color);
