    overflow: hidden;
    font-size: 0;
    border-radius: @corner-radius-circle;
    &-radius {
      position: absolute;
      right: 0;
      width: @size-2;
      height: @size-2;
      border-radius: @corner-radius-circle;
      overflow: hidden;
      font-size: 0;
      &__top {
